  2184 |   // If the base pointer is non-null, we cannot walk to a null address with an
  2185 |   // inbounds GEP in address space zero.
  2186 |   if (isKnownNonZero(GEP->getPointerOperand(), Depth, Q))
  2187 |     return true;
  2188 | 
  2189 |   // Walk the GEP operands and see if any operand introduces a non-zero offset.
  2190 |   // If so, then the GEP cannot produce a null pointer, as doing so would
  2191 |   // inherently violate the inbounds contract within address space zero.
  2192 |   for (gep_type_iterator GTI = gep_type_begin(GEP), GTE = gep_type_end(GEP);
  2193 |        GTI != GTE; ++GTI) {
