  2195 |     if (StructType *STy = GTI.getStructTypeOrNull()) {
  2196 |       ConstantInt *OpC = cast<ConstantInt>(GTI.getOperand());
  2197 |       unsigned ElementIdx = OpC->getZExtValue();
  2198 |       const StructLayout *SL = Q.DL.getStructLayout(STy);
  2199 |       uint64_t ElementOffset = SL->getElementOffset(ElementIdx);
  2200 |       if (ElementOffset > 0)
  2201 |         return true;
  2202 |       continue;
  2203 |     }
  2204 | 
  2205 |     // If we have a zero-sized type, the index doesn't matter. Keep looping.
  2206 |     if (Q.DL.getTypeAllocSize(GTI.getIndexedType()).isZero())
  2207 |       continue;
  2208 | 
  2209 |     // Fast path the constant operand case both for efficiency and so we don't
  2210 |     // increment Depth when just zipping down an all-constant GEP.
  2211 |     if (ConstantInt *OpC = dyn_cast<ConstantInt>(GTI.getOperand())) {
  2212 |       if (!OpC->isZero())
  2213 |         return true;
  2214 |       continue;
  2215 |     }
  2216 | 
  2217 |     // We post-increment Depth here because while isKnownNonZero increments it
  2218 |     // as well, when we pop back up that increment won't persist. We don't want
  2219 |     // to recurse 10k times just because we have 10k GEP operands. We don't
  2220 |     // bail completely out because we want to handle constant GEPs regardless
