  2339 | /// Try to detect a recurrence that monotonically increases/decreases from a
  2340 | /// non-zero starting value. These are common as induction variables.
  2341 | static bool isNonZeroRecurrence(const PHINode *PN) {
  2342 |   BinaryOperator *BO = nullptr;
  2343 |   Value *Start = nullptr, *Step = nullptr;
  2344 |   const APInt *StartC, *StepC;
  2345 |   if (!matchSimpleRecurrence(PN, BO, Start, Step) ||
  2346 |       !match(Start, m_APInt(StartC)) || StartC->isZero())
  2347 |     return false;
  2348 | 
  2349 |   switch (BO->getOpcode()) {
  2350 |   case Instruction::Add:
  2351 |     // Starting from non-zero and stepping away from zero can never wrap back
  2352 |     // to zero.
  2353 |     return BO->hasNoUnsignedWrap() ||
  2354 |            (BO->hasNoSignedWrap() && match(Step, m_APInt(StepC)) &&
  2355 |             StartC->isNegative() == StepC->isNegative());
  2356 |   case Instruction::Mul:
  2357 |     return (BO->hasNoUnsignedWrap() || BO->hasNoSignedWrap()) &&
  2358 |            match(Step, m_APInt(StepC)) && !StepC->isZero();
  2359 |   case Instruction::Shl:
  2360 |     return BO->hasNoUnsignedWrap() || BO->hasNoSignedWrap();
  2361 |   case Instruction::AShr:
  2362 |   case Instruction::LShr:
  2363 |     return BO->isExact();
  2364 |   default:
  2365 |     return false;
  2366 |   }
  2367 | }
