  2369 | static bool isNonZeroAdd(const APInt &DemandedElts, unsigned Depth,
  2370 |                          const SimplifyQuery &Q, unsigned BitWidth, Value *X,
  2371 |                          Value *Y, bool NSW) {
  2372 |   KnownBits XKnown = computeKnownBits(X, DemandedElts, Depth, Q);
  2373 |   KnownBits YKnown = computeKnownBits(Y, DemandedElts, Depth, Q);
  2374 | 
  2375 |   // If X and Y are both non-negative (as signed values) then their sum is not
  2376 |   // zero unless both X and Y are zero.
  2377 |   if (XKnown.isNonNegative() && YKnown.isNonNegative())
  2378 |     if (isKnownNonZero(Y, DemandedElts, Depth, Q) ||
  2379 |         isKnownNonZero(X, DemandedElts, Depth, Q))
  2380 |       return true;
  2381 | 
  2382 |   // If X and Y are both negative (as signed values) then their sum is not
  2383 |   // zero unless both X and Y equal INT_MIN.
  2384 |   if (XKnown.isNegative() && YKnown.isNegative()) {
  2385 |     APInt Mask = APInt::getSignedMaxValue(BitWidth);
  2386 |     // The sign bit of X is set.  If some other bit is set then X is not equal
  2387 |     // to INT_MIN.
  2388 |     if (XKnown.One.intersects(Mask))
  2389 |       return true;
  2390 |     // The sign bit of Y is set.  If some other bit is set then Y is not equal
  2391 |     // to INT_MIN.
  2392 |     if (YKnown.One.intersects(Mask))
  2393 |       return true;
  2394 |   }
  2395 | 
  2396 |   // The sum of a non-negative number and a power of two is not zero.
  2397 |   if (XKnown.isNonNegative() &&
  2398 |       isKnownToBeAPowerOfTwo(Y, /*OrZero*/ false, Depth, Q))
  2399 |     return true;
  2400 |   if (YKnown.isNonNegative() &&
  2401 |       isKnownToBeAPowerOfTwo(X, /*OrZero*/ false, Depth, Q))
  2402 |     return true;
  2403 | 
  2404 |   return KnownBits::computeForAddSub(/*Add*/ true, NSW, XKnown, YKnown)
  2405 |       .isNonZero();
  2406 | }
